SELECT COUNT(*) AS library_count
FROM libraries
WHERE organism_id = (SELECT organism_id FROM organisms WHERE organism_name = 'Solanum lycopersicum');

SELECT COUNT(*) 
FROM unigenes 
WHERE curator = 'Dr. Bob';

SELECT library_size AS total_ests
FROM libraries
WHERE library_id = 1;

SELECT library_type_name, description
FROM library_types
WHERE is_active = 1;
